// Log movement script - moves LEFT continuously
// Wraps around screen edges for seamless looping

export function onUpdate(entity: Entity, dt: number) {
  // Move left at configured speed
  entity.transform.x -= speed;

  // Wrap around when off-screen to the left
  if (entity.transform.x < wrapMinX) {
    entity.transform.x = wrapMaxX;
  }
}

// Exported variables for tuning
export const speed = 2;        // Pixels per frame moving left
export const wrapMinX = -120;  // Reset position when x goes below this
export const wrapMaxX = 850;   // Reset to this x position

